 41→    private fun handleCommand(intent: Intent) {
 42→        val accountUuid = intent.getStringExtra(EXTRA_ACCOUNT_UUID)
 43→        if (accountUuid == null) {
 44→            Timber.w("Missing account UUID.")
 45→            return
 46→        }
 47→
 48→        val account = preferences.getAccount(accountUuid)
 49→        if (account == null) {
 50→            Timber.w("Could not find account for notification action.")
 51→            return
 52→        }
 53→
 54→        when (intent.action) {
 55→            ACTION_MARK_AS_READ -> markMessagesAsRead(intent, account)
 56→            ACTION_DELETE -> deleteMessages(intent)
 57→            ACTION_ARCHIVE -> archiveMessages(intent)
 58→            ACTION_SPAM -> markMessageAsSpam(intent, account)
 59→            ACTION_DISMISS -> Timber.i("Notification dismissed")
 60→        }
 61→
 62→        cancelNotifications(intent, account)
 63→    }
 64→
 65→    override fun onBind(intent: Intent): IBinder? {
 66→        return null
 67→    }
