1150→    public void setFlag(Account account, long folderId, List<LocalMessage> messages, Flag flag, boolean newState) {
1151→        // TODO: Put this into the background, but right now some callers depend on the message
1152→        //       objects being modified right after this method returns.
1153→        try {
1154→            LocalStore localStore = localStoreProvider.getInstance(account);
1155→            LocalFolder localFolder = localStore.getFolder(folderId);
1156→            localFolder.open();
1157→
1158→            // Update the messages in the local store
1159→            localFolder.setFlags(messages, Collections.singleton(flag), newState);
1160→
1161→            for (MessagingListener l : getListeners()) {
1162→                l.folderStatusChanged(account, folderId);
1163→            }
1164→
1165→            // Handle the remote side
1166→            if (supportsFlags(account) && !localFolder.isLocalOnly()) {
1167→                List<String> uids = getUidsFromMessages(messages);
1168→                queueSetFlag(account, folderId, newState, flag, uids);
1169→                processPendingCommands(account);
1170→            }
1171→        } catch (MessagingException me) {
1172→            throw new RuntimeException(me);
1173→        }
1174→    }
